/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rooms` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `hostel_id` bigint NOT NULL,
  `room_number` varchar(20) NOT NULL,
  `capacity` int NOT NULL DEFAULT '2',
  `current_occupancy` int NOT NULL DEFAULT '0',
  `room_gender` enum('MALE','FEMALE') NOT NULL,
  `mattress_type` enum('NORMAL','QUEEN') NOT NULL DEFAULT 'NORMAL',
  `has_ac` tinyint(1) NOT NULL DEFAULT '0',
  `has_wifi` tinyint(1) NOT NULL DEFAULT '1',
  `status` enum('AVAILABLE','FULL') NOT NULL DEFAULT 'AVAILABLE',
  `price` decimal(10,2) NOT NULL DEFAULT '0.00',
  `floor_number` int NOT NULL DEFAULT '1',
  `version` bigint NOT NULL DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `room_type` varchar(20) NOT NULL DEFAULT 'STANDARD' COMMENT 'Room classification: STANDARD, SINGLE, DOUBLE, SUITE, DORMITORY',
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_room` (`hostel_id`,`room_number`),
  KEY `idx_rooms_hostel` (`hostel_id`),
  KEY `idx_rooms_gender` (`room_gender`),
  KEY `idx_rooms_status` (`status`),
  CONSTRAINT `fk_rooms_hostel` FOREIGN KEY (`hostel_id`) REFERENCES `hostels` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=192 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

